        % Button pushed function: logButton
        function logButtonPushed(app, event)
   x = str2double(app.EditField.Value);  

    if isnan(x) || x <= 0
        app.EditField.Value = "Error";    
    else
        app.EditField.Value = string(log(x));   
    end

        end

        % Button pushed function: Button_10
        function Button_10Pushed(app, event)
   Existingstring =app.EditField.Value;
   newstring =('^');
   textstring = strcat(Existingstring,newstring);
   app.EditField.Value = textstring;          
        end

        % Button pushed function: cosButton
        function cosButtonPushed(app, event)
   value = str2double(app.EditField.Value);
if isnan(value)
    uialert(app.UIFigure,'Please enter a valid number','Error');
else
    result = cosd(value);                   
    app.EditField.Value = num2str(result);
end         
        end

        % Button pushed function: tanButton
        function tanButtonPushed(app, event)
            value = str2double(app.EditField.Value);
if isnan(value)
    uialert(app.UIFigure,'Please enter a valid number','Error');
else
    result = tand(value);                    
    app.EditField.Value = num2str(result);
end

        end

        % Button pushed function: sinButton
        function sinButtonPushed(app, event)
   value = str2double(app.EditField.Value); 
       if isnan(value)
           uialert(app.UIFigure,'Please enter a valid number','Error');
       else
           result = sind(value);                 
            app.EditField.Value = num2str(result); 
       end            
        end

        % Button pushed function: Button_15
        function Button_15Pushed(app, event)
  current = app.EditField.Value;       

    if isempty(current)
        return;  
    end
    openCount = count(current, '(');
    closeCount = count(current, ')');
    if openCount > closeCount
        app.EditField.Value = current + ")";  
    else
    end

        end

        % Button pushed function: Button_14
        function Button_14Pushed(app, event)
     current = app.EditField.Value;

    if isempty(current) || current(end)=='+' || current(end)=='-' || current(end)=='*' || current(end)=='/'
        app.EditField.Value = current + "pi";
    else
        app.EditField.Value = current + "*pi";   % auto multiply
    end

        end

        % Button pushed function: ClearButton
        function ClearButtonPushed(app, event)
            app.EditField.Value =(' ');             
        end

        % Button pushed function: PLOTSINButton
        function PLOTSINButtonPushed(app, event)
   x = linspace(0, 2*pi, 500);   
    y = sin(x);                  

    plot(app.UIAxes, x, y);      
    grid(app.UIAxes, 'on');

    xlabel(app.UIAxes, 'x');
    ylabel(app.UIAxes, 'sin(x)');
    title(app.UIAxes, 'Sin Function')          
        end

        % Button pushed function: PLOTCOSButton
        function PLOTCOSButtonPushed(app, event)
     x = linspace(0, 2*pi, 500);   
    y = cos(x);                  

    plot(app.UIAxes, x, y);      
    grid(app.UIAxes, 'on');

    xlabel(app.UIAxes, 'x');
    ylabel(app.UIAxes, 'cos(x)');
    title(app.UIAxes, 'COS Function');            

        end

        % Button pushed function: PLOTTANButton
        function PLOTTANButtonPushed(app, event)
 fplot(app.UIAxes, @(x) tan(x), [0 2*pi]);
ylim(app.UIAxes, [-10 10]);
grid(app.UIAxes, 'on');       
        end

        % Button pushed function: sqrtButton
        function sqrtButtonPushed(app, event)
       value = str2double(app.EditField.Value);  
if isnan(value)
    uialert(app.UIFigure,'Please enter a valid number','Error');
else
    result = sqrt(value);               
    app.EditField.Value = num2str(result);
end

        end
    end

